288	  useEffect(() => {
289	    if (inView) return;
290	    setAutoRotate(true);
291	  }, [inView]);
292	
293	  useEffect(() => {
294	    if (!inView || !autoRotate) return;
295	    const cascadeMs =
296	      Math.max(0, active.demo.messages.length - 1) *
297	      (TYPING_DELAY_MS + TYPING_DURATION_MS);
298	    const dwellMs = 2500;
299	    const id = window.setTimeout(() => {
300	      setActiveId((current) => {
301	        const idx = PLATFORMS.findIndex((p) => p.id === current);
302	        return PLATFORMS[(idx + 1) % PLATFORMS.length].id;
