343	function useSectionInView(
344	  ref: React.RefObject<HTMLElement | null>,
345	  threshold: number,
346	): boolean {
347	  const [inView, setInView] = useState(false);
348	
349	  useEffect(() => {
350	    const node = ref.current;
351	    if (!node) return;
352	    if (typeof IntersectionObserver === "undefined") {
353	      setInView(true);
354	      return;
355	    }
356	    const observer = new IntersectionObserver(
357	      ([entry]) => setInView(entry?.isIntersecting ?? false),
358	      { threshold },
359	    );
360	    observer.observe(node);
361	    return () => observer.disconnect();
362	  }, [ref, threshold]);
363	
364	  return inView;
365	}
