367	function FloatingCTA({
368	  isFloating,
369	  action,
370	  actionKey,
371	  iconSrc,
372	  comingSoon,
373	}: {
374	  isFloating: boolean;
375	  action: ActionLink;
376	  actionKey: string;
377	  iconSrc: string | undefined;
378	  comingSoon?: boolean;
379	}) {
380	  // Reserve the static-flow slot so the layout never jumps when the button
381	  // pops out of the flow into a fixed position. The CTA is rendered twice:
382	  //   - In flow, invisible while floating (reserves space)
383	  //   - Fixed at the bottom while floating, fades in via opacity only
384	  return (
385	    <div className="relative flex w-full justify-center pt-2">
386	      <div
387	        aria-hidden={isFloating}
388	        className={isFloating ? "pointer-events-none opacity-0" : "opacity-100"}
389	      >
390	        <PlatformCTASwitcher
391	          actionKey={actionKey}
392	          action={action}
393	          iconSrc={iconSrc}
394	          comingSoon={comingSoon}
395	        />
396	      </div>
397	
398	      <AnimatePresence initial={false}>
399	        {isFloating && (
400	          <m.div
401	            key="floating"
402	            initial={{ opacity: 0 }}
403	            animate={{ opacity: 1 }}
404	            exit={{ opacity: 0 }}
405	            transition={{ duration: 0.18, ease: "easeOut" }}
406	            className="pointer-events-none fixed inset-x-0 bottom-6 z-[1001] flex justify-center px-4"
407	          >
408	            <div className="pointer-events-auto">
409	              <PlatformCTASwitcher
410	                actionKey={actionKey}
411	                action={action}
412	                iconSrc={iconSrc}
413	                comingSoon={comingSoon}
414	              />
415	            </div>
416	          </m.div>
417	        )}
418	      </AnimatePresence>
419	    </div>
420	  );
421	}
