449	function useFloatingCta(
450	  phoneRef: React.RefObject<HTMLDivElement | null>,
451	): boolean {
452	  const [floating, setFloating] = useState(false);
453	
454	  useEffect(() => {
455	    const phone = phoneRef.current;
456	    if (!phone) return;
457	
458	    const update = (): void => {
459	      const phoneRect = phone.getBoundingClientRect();
460	      const vh = window.innerHeight;
461	      // Threshold is tuned so the floating button and its static-flow slot
462	      // line up vertically at the moment of switch — the visual position
463	      // doesn't jump.
464	      const phoneEnoughVisible = phoneRect.top < vh - 200;
465	      // The floating button sits at vh - 56 (bottom-6 + button height). The
466	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
467	      // button). The switch happens when the two y positions match.
468	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
469	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
470	    };
471	
472	    update();
473	    window.addEventListener("scroll", update, { passive: true });
474	    window.addEventListener("resize", update);
475	    return () => {
476	      window.removeEventListener("scroll", update);
477	      window.removeEventListener("resize", update);
478	    };
479	  }, [phoneRef]);
480	
481	  return floating;
482	}
