484	const TYPING_DELAY_MS = 450;
485	const TYPING_DURATION_MS = 850;
486	
487	function useStaggeredMessages(
488	  platform: Platform,
489	  enabled: boolean,
490	): ChatMessageItem[] {
491	  const allMessages = platform.demo.messages;
492	  const [visibleCount, setVisibleCount] = useState(1);
493	  const [showTyping, setShowTyping] = useState(false);
494	
495	  useEffect(() => {
496	    setVisibleCount(1);
497	    setShowTyping(false);
498	    if (!enabled) return;
499	    if (allMessages.length <= 1) return;
500	
501	    const timers: ReturnType<typeof setTimeout>[] = [];
502	    let elapsed = 0;
503	    for (let i = 1; i < allMessages.length; i++) {
504	      elapsed += TYPING_DELAY_MS;
505	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
506	      elapsed += TYPING_DURATION_MS;
507	      timers.push(
508	        setTimeout(() => {
509	          setShowTyping(false);
510	          setVisibleCount((c) => c + 1);
511	        }, elapsed),
512	      );
513	    }
514	
515	    return () => {
516	      for (const t of timers) clearTimeout(t);
517	    };
518	  }, [allMessages, enabled]);
519	
520	  return useMemo(() => {
521	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
522	      ...m,
523	      id: m.id ?? `msg-${i}`,
524	    }));
525	    if (!showTyping || visibleCount >= allMessages.length) return real;
526	    const next = allMessages[visibleCount];
527	    return [
528	      ...real,
529	      {
530	        id: `typing-${visibleCount}`,
531	        from: next.from,
532	        author: next.author,
533	        avatar: next.avatar,
534	        authorColor: next.authorColor,
535	        typing: true,
536	      },
537	    ];
538	  }, [allMessages, visibleCount, showTyping]);
539	}
