555	    >
556	      {platforms.map((p) => {
557	        const isActive = p.id === activeId;
558	        return (
559	          <Chip
560	            key={p.id}
561	            variant={isActive ? "solid" : "flat"}
562	            color={isActive ? "primary" : "default"}
563	            size="lg"
564	            role="tab"
565	            aria-selected={isActive}
566	            onClick={() => onSelect(p.id)}
567	            className="cursor-pointer select-none"
568	            startContent={
569	              typeof p.icon === "string" ? (
570	                <Image
571	                  src={p.icon}
572	                  alt=""
573	                  width={20}
574	                  height={20}
575	                  className="h-5 w-5 shrink-0 rounded"
576	                  aria-hidden
577	                />
578	              ) : (
579	                <span
580	                  className="flex h-5 w-5 shrink-0 items-center justify-center"
581	                  aria-hidden
582	                >
583	                  {p.icon}
584	                </span>
585	              )
586	            }
587	          >
588	            {p.name}
589	          </Chip>
590	        );
591	      })}
592	    </div>
593	  );
594	}
595	
596	function PhoneFrame({
597	  platform,
598	  messages,
599	}: {
600	  platform: Platform;
601	  messages: ChatMessageItem[];
602	}) {
