604	    <div className="relative isolate sm:pb-[82px]">
605	      <div
606	        aria-hidden
607	        className="-z-10 pointer-events-none absolute -inset-x-[28rem] -inset-y-[20rem]"
608	        style={{
609	          backgroundImage:
610	            "radial-gradient(closest-side, rgba(0,187,255,0.7), rgba(0,187,255,0.25) 35%, rgba(0,187,255,0.06) 65%, transparent 80%)",
611	          filter: "blur(18px)",
612	        }}
613	      />
614	      <IPhoneMockup
615	        screenBackground={platform.phone.screenBackground}
616	        statusBarTone={platform.phone.statusBarTone}
617	        className="sm:scale-[1.1] sm:origin-top"
618	      >
619	        <AnimatePresence mode="wait" initial={false}>
620	          <m.div
621	            key={platform.id}
622	            className="flex h-full flex-col"
623	            initial={{ opacity: 0, y: 8 }}
624	            animate={{ opacity: 1, y: 0 }}
625	            exit={{ opacity: 0, y: -8 }}
626	            transition={{ duration: 0.2, ease: "easeOut" }}
627	          >
628	            <ChatDemo
629	              platform={platform.id}
630	              title={platform.demo.title}
631	              subtitle={platform.demo.subtitle}
