673	        {iconSrc && (
674	          <Image
675	            src={iconSrc}
676	            alt=""
677	            width={28}
678	            height={28}
679	            aria-hidden
680	            className="h-7 w-7 shrink-0 rounded"
681	          />
682	        )}
683	        {action.label}
