() => {
  const section = document.querySelector('section');
  // find element with text "Reach GAIA from anywhere"
  const headers = Array.from(document.querySelectorAll('h2'));
  const target = headers.find(h => h.textContent?.includes('Reach GAIA'));
  if (target) {
    const sec = target.closest('section');
    sec?.scrollIntoView({ behavior: 'instant', block: 'start' });
    return { found: true, top: sec?.getBoundingClientRect().top };
  }
  return { found: false };
}

() => {
  // scroll a bit so the CTA is visible
  window.scrollBy(0, 300);
  return window.scrollY;
}

() => {
  const prev = Array.from(document.querySelectorAll('button')).find(b => b.getAttribute('aria-label') === 'Previous platform');
  const next = Array.from(document.querySelectorAll('button')).find(b => b.getAttribute('aria-label') === 'Next platform');
  const cta = Array.from(document.querySelectorAll('a')).find(a => /Message on/i.test(a.textContent || '') || /Coming Soon/i.test(a.textContent || ''));
  if (!prev || !next) return { error: 'buttons not found' };
  const prevR = prev.getBoundingClientRect();
  const nextR = next.getBoundingClientRect();
  const ctaR = cta?.getBoundingClientRect();
  // also find the wrapper that contains the CTA group
  let wrapper = prev.parentElement;
  while (wrapper && !wrapper.classList.contains('relative')) wrapper = wrapper.parentElement;
  const wrapR = wrapper?.getBoundingClientRect();
  // Find the iPhone mockup width
  const iphone = document.querySelector('[style*="width: 390"]');
  const iphoneR = iphone?.getBoundingClientRect();
  return {
    prev: { left: prevR.left, right: prevR.right, top: prevR.top, w: prevR.width },
    next: { left: nextR.left, right: nextR.right, top: nextR.top, w: nextR.width },
    cta: ctaR ? { left: ctaR.left, right: ctaR.right, top: ctaR.top, w: ctaR.width } : null,
    wrapper: wrapR ? { left: wrapR.left, right: wrapR.right, w: wrapR.width, classes: wrapper?.className } : null,
    iphone: iphoneR ? { left: iphoneR.left, right: iphoneR.right, w: iphoneR.width } : null,
    viewportW: window.innerWidth,
  };
}

