function pickColor(seed: string) {
  const palette = [
    "#5865F2",
    "#EB459E",
    "#F23F42",
    "#23A55A",
    "#F0B232",
    "#FF7C5C",
    "#9B7CFF",
    "#1ABC9C",
    "#3498DB",
    "#E74C3C",
  ];
  let hash = 0;
  for (let i = 0; i < seed.length; i++)
    hash = (hash << 5) - hash + seed.charCodeAt(i);
  return palette[Math.abs(hash) % palette.length];
}

